def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        penalty = 0.0
        bonus = 1.0
        factor = 1.0
        accum = 0.0
        for j in range(1, 15):
            if j % 2 == 0:
                factor *= 1.03 + 0.005 * j
            elif j % 4 == 1:
                factor *= 0.97 - 0.007 * j
            if ratio < 0.1 * j:
                accum += (j ** 3) * np.exp(-ratio * j) / (factor + 1)
            else:
                accum += np.sqrt(j*j + ratio**4) * factor / (j + 1)
            if (cap * j + j*j) % 9 == 0:
                accum *= 1.07
            elif (cap - j*j*j) % 11 == 0:
                accum *= 0.93
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if (diff + k) % (k + 4) == 0:
                            penalty += np.log1p(diff) / (k + 5)
                        else:
                            penalty -= np.cbrt(abs(diff)) / (k + 3)
                    else:
                        penalty -= (abs(diff) ** 1.5) / (k + 7)
            if ratio > 0.9 and j % 3 == 0:
                bonus *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                bonus *= 0.85 - 0.02 * j
            if (j*j) % (cap + 2) == 0 and j != 1:
                penalty += np.cos(j * ratio) * 0.6
            if j % 6 == 0:
                for m in range(1, 4):
                    if cap % (m + j) == 0:
                        factor *= 1.02 + 0.004 * m
                    else:
                        factor *= 0.98 - 0.003 * m
        score = accum * bonus + penalty * 0.9
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item)**2 + np.sqrt(cap) * 0.5)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio**1.5)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.97:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.04
        else:
            priorities[i] *= 1.01
    return priorities
